//! `baton-list` — list iRODS data objects and collections.
//!
//! Session 3a scaffolds the CLI harness, NDJSON streaming loop, and
//! tracing initialisation. The listing flags (`--size`, `--checksum`,
//! `--avu`, ...) are all accepted by clap so the CLI surface stays
//! stable across 3a/3b/3c, but at this point each line is echoed
//! through unchanged — `rcObjStat` wiring lands in the next two
//! commits.

use std::io::{BufRead, Write};

use anyhow::{Context, Result};
use clap::Parser;
use tracing_subscriber::EnvFilter;

#[derive(Parser, Debug)]
#[command(name = "baton-list", about = "List iRODS data objects and collections")]
struct Args {
    /// Include object size in the output.
    #[arg(long)]
    size: bool,

    /// Include object checksum in the output.
    #[arg(long)]
    checksum: bool,

    /// Include AVUs in the output. Parsed here; implementation arrives in Session 3b.
    #[arg(long)]
    avu: bool,

    /// Include ACL entries in the output. Parsed here; implementation arrives in Session 3b.
    #[arg(long)]
    acl: bool,

    /// Include replicate info in the output. Parsed here; implementation arrives in Session 3b.
    #[arg(long)]
    replicate: bool,

    /// Include timestamps in the output. Parsed here; implementation arrives in Session 3b.
    #[arg(long)]
    timestamp: bool,

    /// Recurse into collection contents. Parsed here; implementation arrives in Session 3c.
    #[arg(long)]
    contents: bool,

    /// Verbose logging (DEBUG level).
    #[arg(short, long, conflicts_with = "silent")]
    verbose: bool,

    /// Silent logging (ERROR level only).
    #[arg(long)]
    silent: bool,
}

impl Args {
    fn log_level(&self) -> &'static str {
        if self.silent {
            "error"
        } else if self.verbose {
            "debug"
        } else {
            "info"
        }
    }
}

fn init_tracing(args: &Args) {
    // `RUST_LOG` overrides the CLI flags if set — matches standard tracing
    // behaviour so downstream debugging stays consistent.
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new(args.log_level()));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_writer(std::io::stderr)
        .init();
}

fn main() -> Result<()> {
    let args = Args::parse();
    init_tracing(&args);

    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();

    for line in stdin.lock().lines() {
        let line = line.context("reading stdin")?;
        if line.trim().is_empty() {
            continue;
        }

        // Parse as a generic JSON value for now. Typed parsing into
        // DataObject / Collection arrives alongside operations/list.rs
        // in the next commit.
        let value: serde_json::Value =
            serde_json::from_str(&line).context("parsing input line as JSON")?;

        serde_json::to_writer(&mut out, &value).context("writing output line")?;
        writeln!(&mut out).context("writing newline")?;
    }

    Ok(())
}
